import{_ as t,o as e,i as o,aB as c}from"./chunks/framework._ZAOES46.js";const p=JSON.parse('{"title":"FaDescriptions 描述列表","description":"","frontmatter":{},"headers":[],"relativePath":"components/basic/FaDescriptions.md","filePath":"components/basic/FaDescriptions.md"}'),a={name:"components/basic/FaDescriptions.md"};function l(r,d,i,s,n,h){return e(),o("div",null,[...d[0]||(d[0]=[c('<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /components/basic/FaDescriptions.md for this page in Markdown format</div><h1 id="fadescriptions-描述列表" tabindex="-1">FaDescriptions 描述列表 <a class="header-anchor" href="#fadescriptions-描述列表" aria-label="Permalink to “FaDescriptions 描述列表”">​</a></h1><p>纯展示信息组件，用于详情页、资料卡片、审核信息等只读数据场景。支持横向与纵向布局、边框、跨列、具名插槽和单项扩展字段。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>用户、订单、商品等详情信息展示</li><li>表单提交后的只读确认信息</li><li>弹窗中的轻量信息摘要</li><li>卡片内的结构化字段展示</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>items</code></td><td><code>DescriptionItem[]</code></td><td><code>[]</code></td><td>描述项配置</td></tr><tr><td><code>column</code></td><td><code>number</code></td><td><code>3</code></td><td>每行展示的描述项数量</td></tr><tr><td><code>direction</code></td><td><code>&#39;horizontal&#39; | &#39;vertical&#39;</code></td><td><code>&#39;horizontal&#39;</code></td><td>布局方向</td></tr><tr><td><code>border</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否显示边框和单元格分割线</td></tr><tr><td><code>labelWidth</code></td><td><code>string | number</code></td><td>-</td><td>label 区域宽度，仅横向布局生效</td></tr><tr><td><code>size</code></td><td><code>&#39;sm&#39; | &#39;default&#39; | &#39;lg&#39;</code></td><td><code>&#39;default&#39;</code></td><td>单元格密度</td></tr><tr><td><code>emptyText</code></td><td><code>string</code></td><td><code>&#39;-&#39;</code></td><td>value 为空时的占位文本</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>根节点 class</td></tr><tr><td><code>labelClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>全局 label 单元格 class</td></tr><tr><td><code>valueClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>全局 value 单元格 class</td></tr></tbody></table><h2 id="descriptionitem" tabindex="-1">DescriptionItem <a class="header-anchor" href="#descriptionitem" aria-label="Permalink to “DescriptionItem”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>key</code></td><td><code>string</code></td><td>插槽标识。使用具名插槽时需要提供，组件不会自动转换</td></tr><tr><td><code>label</code></td><td><code>string</code></td><td>label 文本</td></tr><tr><td><code>value</code></td><td><code>string | number | boolean | null | undefined</code></td><td>value 文本</td></tr><tr><td><code>span</code></td><td><code>number</code></td><td>占用几个描述项列，默认 <code>1</code></td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>当前项 label 和 value 的公共 class</td></tr><tr><td><code>labelClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>当前项 label 单元格 class</td></tr><tr><td><code>valueClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>当前项 value 单元格 class</td></tr></tbody></table><p><code>DescriptionItem</code> 支持扩展字段，扩展字段会原样保留在插槽参数的 <code>item</code> 中。</p><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th><th>作用域参数</th></tr></thead><tbody><tr><td><code>label-{key}</code></td><td>自定义指定项 label</td><td><code>item</code>、<code>index</code>、<code>label</code>、<code>value</code></td></tr><tr><td><code>value-{key}</code></td><td>自定义指定项 value</td><td><code>item</code>、<code>index</code>、<code>label</code>、<code>value</code></td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><code>key</code> 只用于生成具名插槽，不用于读取数据。</li><li><code>key</code> 不会自动转换，建议使用字母、数字、短横线和下划线。</li><li><code>value</code> 为 <code>null</code>、<code>undefined</code> 或空字符串时显示 <code>emptyText</code>；<code>0</code> 和 <code>false</code> 会正常显示。</li><li><code>span</code> 表示占用几个描述项列，超出 <code>column</code> 时会按 <code>column</code> 处理。</li><li>最后一行不足 <code>column</code> 时会自动补齐空单元格，保证边框网格完整。</li><li>组件不内置标题、空状态和点击事件，可与 <code>FaCard</code>、<code>FaEmpty</code> 等组件组合使用。</li></ol>',14)])])}const m=t(a,[["render",l]]);export{p as __pageData,m as default};
